// // This T Flip-Flop toggles the stored value on the negative edge of the clock signal when the toggle input is 1. The clear signal asynchronously sets the stored value to 1.
module t_ff(
    input clk,
    input clr,
    input t,

    output q
);

reg q;

always @(posedge clk or posedge clr)
begin
  if (clr)
    q <= 1'b0;
  else if (t)
    q <= ~q;
end

endmodule
